script:
(function() {
  fetch('assets/txts/xfiles.txt')
    .then(function(response) { return response.text(); })
    .then(function(art) {
      var pre = document.createElement('pre');
      pre.className = 'terminal-ascii';
      pre.style.color = '#0f0';
      pre.style.background = '#111';
      pre.style.fontFamily = 'monospace';
      pre.style.fontSize = '1em';
      pre.style.lineHeight = '1.1';
      pre.style.padding = '1em';
      pre.textContent = art;
      document.getElementById('terminal-output').appendChild(pre);
      document.getElementById('terminal-output').scrollTop = document.getElementById('terminal-output').scrollHeight;
      var audio = document.getElementById('xfiles-audio');
      if (audio) {
        audio.pause();
        audio.currentTime = 0;
        audio.parentNode.removeChild(audio);
      }
      audio = document.createElement('audio');
      audio.id = 'xfiles-audio';
      audio.src = 'assets/audio/xfiles.mp3';
      audio.volume = 0.7;
      audio.autoplay = true;
      audio.style.display = 'none';
      document.body.appendChild(audio);
    });
})();
